from pathlib import Path
from typing import List

from scripts.utils import fetch_html, load_cache, parse_trending, save_cache, utc_now_iso

BASE_URL = "https://github.com/trending"
CACHE_PATH = Path(__file__).resolve().parent / "cache_daily.json"


def build_url(language: str) -> str:
    if language and language.lower() != "all":
        return f"{BASE_URL}/{language}?since=daily"
    return f"{BASE_URL}?since=daily"


def format_daily(items: List[dict], language: str, limit: int) -> str:
    header = f"## GitHub Trending 日榜（UTC {utc_now_iso()}）\n"
    header += f"语言：{language if language else 'All'}\n\n"
    if not items:
        return header + "暂无数据。"
    lines = [header]
    for idx, item in enumerate(items[:limit], start=1):
        name = item.get("name") or "(unknown)"
        description = item.get("description") or "暂无描述"
        language_text = item.get("language") or "未知"
        stars_total = item.get("stars_total") or 0
        stars_today = item.get("stars_period") or 0
        lines.append(
            f"{idx}. **{name}** - {description} "
            f"(语言: {language_text}, ⭐ {stars_total}, 今日+{stars_today})"
        )
    lines.append("\n趋势标签：今日热榜")
    return "\n".join(lines)


def run(language: str = "All", limit: int = 10) -> str:
    url = build_url(language)
    try:
        html = fetch_html(url)
        items = parse_trending(html)
        payload = {
            "last_fetched": utc_now_iso(),
            "language": language,
            "items": items,
        }
        save_cache(CACHE_PATH, payload)
        return format_daily(items, language, limit)
    except Exception:
        cached = load_cache(CACHE_PATH)
        if cached and "items" in cached:
            notice = "\n\n> 网络失败，返回上一次缓存结果。"
            return format_daily(cached["items"], cached.get("language", language), limit) + notice
        return "抓取失败，请稍后再试。"


if __name__ == "__main__":
    print(run())

from pathlib import Path
from typing import Dict, List

from scripts.utils import (
    fetch_html,
    load_cache,
    parse_trending,
    save_cache,
    sleep_if_needed,
    utc_now_iso,
)

BASE_URL = "https://github.com/trending"
CACHE_PATH = Path(__file__).resolve().parent / "cache_monthly.json"
DEFAULT_LANGUAGES = [
    "Python",
    "JavaScript",
    "TypeScript",
    "Go",
    "Rust",
    "Java",
    "C++",
    "C#",
    "PHP",
    "Ruby",
]


def build_url(language: str) -> str:
    if language and language.lower() != "all":
        return f"{BASE_URL}/{language}?since=monthly"
    return f"{BASE_URL}?since=monthly"


def aggregate_items(items: List[dict], stats: Dict[str, dict]) -> None:
    for item in items:
        name = item.get("name") or ""
        if not name:
            continue
        entry = stats.setdefault(
            name,
            {
                "name": name,
                "description": item.get("description") or "暂无描述",
                "language": item.get("language") or "未知",
                "count": 0,
                "stars_total": 0,
                "stars_period": 0,
            },
        )
        entry["count"] += 1
        entry["stars_period"] += int(item.get("stars_period") or 0)
        entry["stars_total"] = max(entry["stars_total"], int(item.get("stars_total") or 0))


def format_monthly(items: List[dict], language: str, limit: int, note: str = "") -> str:
    header = f"## GitHub Trending 月度汇总（UTC {utc_now_iso()}）\n"
    header += f"语言：{language if language else 'All'}\n\n"
    if not items:
        return header + "暂无数据。"
    lines = [header]
    for idx, item in enumerate(items[:limit], start=1):
        name = item.get("name") or "(unknown)"
        description = item.get("description") or "暂无描述"
        language_text = item.get("language") or "未知"
        stars_total = item.get("stars_total") or 0
        stars_period = item.get("stars_period") or 0
        count = item.get("count") or 0
        lines.append(
            f"{idx}. **{name}** - {description} "
            f"(语言: {language_text}, ⭐ {stars_total}, 本月+{stars_period}, 出现{count}次)"
        )
    lines.append("\n趋势标签：月度汇总")
    if note:
        lines.append(note)
    return "\n".join(lines)


def run(language: str = "All", limit: int = 10) -> str:
    cache = load_cache(CACHE_PATH) or {"languages": {}, "last_fetched": None}
    languages = [language] if language and language.lower() != "all" else DEFAULT_LANGUAGES
    stats: Dict[str, dict] = {}
    failed_languages = []

    for idx, lang in enumerate(languages):
        url = build_url(lang)
        try:
            html = fetch_html(url)
            items = parse_trending(html)
            cache["languages"][lang] = {
                "last_fetched": utc_now_iso(),
                "items": items,
            }
            aggregate_items(items, stats)
        except Exception:
            cached_lang = cache.get("languages", {}).get(lang)
            if cached_lang and "items" in cached_lang:
                aggregate_items(cached_lang["items"], stats)
            else:
                failed_languages.append(lang)
        if idx < len(languages) - 1:
            sleep_if_needed(3)

    cache["last_fetched"] = utc_now_iso()
    save_cache(CACHE_PATH, cache)

    ranked = sorted(
        stats.values(),
        key=lambda item: (item.get("count", 0), item.get("stars_period", 0), item.get("stars_total", 0)),
        reverse=True,
    )
    note = ""
    if failed_languages:
        note = "\n\n> 部分语言抓取失败：" + ", ".join(failed_languages)
    return format_monthly(ranked, "All" if language.lower() == "all" else language, limit, note)


if __name__ == "__main__":
    print(run())

import argparse
from scripts.daily import run as run_daily from scripts.monthly import run as run_monthly
def main() -> None: parser = argparse.ArgumentParser(description="GitHub Trending Skill Runner") parser.add_argument("--mode", choices=["daily", "monthly"], default="daily") parser.add_argument("--language", default="All") parser.add_argument("--limit", type=int, default=10) args = parser.parse_args()
if args.mode == "daily": output = run_daily(language=args.language, limit=args.limit) else: output = run_monthly(language=args.language, limit=args.limit)
print(output)
if __name__ == "__main__": main()

import json
import re
import time
from datetime import datetime, timezone
from pathlib import Path
from typing import Dict, List, Optional

import requests
from bs4 import BeautifulSoup

DEFAULT_HEADERS = {
    "User-Agent": "github-trending-skill/1.0 (+https://github.com)"
}


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()


def parse_star_count(text: str) -> int:
    if not text:
        return 0
    cleaned = text.strip().lower().replace(",", "")
    match = re.search(r"(\d+(?:\.\d+)?)([km]?)", cleaned)
    if not match:
        return 0
    value = float(match.group(1))
    suffix = match.group(2)
    if suffix == "k":
        value *= 1000
    elif suffix == "m":
        value *= 1000000
    return int(value)


def fetch_html(url: str, timeout: int = 20) -> str:
    response = requests.get(url, headers=DEFAULT_HEADERS, timeout=timeout)
    response.raise_for_status()
    return response.text


def parse_trending(html: str) -> List[Dict[str, object]]:
    soup = BeautifulSoup(html, "html.parser")
    items = []
    for article in soup.select("article.Box-row"):
        name = ""
        link = article.select_one("h2 a")
        if link and link.get("href"):
            name = link["href"].strip("/")
        description = ""
        desc_el = article.select_one("p")
        if desc_el:
            description = " ".join(desc_el.get_text(" ", strip=True).split())
        language = ""
        lang_el = article.select_one("[itemprop=programmingLanguage]")
        if lang_el:
            language = lang_el.get_text(strip=True)
        stars_total = 0
        for star_link in article.select("a[href*='stargazers']"):
            stars_total = parse_star_count(star_link.get_text(strip=True))
            if stars_total:
                break
        stars_period = 0
        period_span = None
        for span in article.select("span"):
            text = span.get_text(" ", strip=True).lower()
            if "stars today" in text or "stars this month" in text:
                period_span = span
                break
        if period_span:
            stars_period = parse_star_count(period_span.get_text(strip=True))
        items.append(
            {
                "name": name,
                "description": description,
                "language": language,
                "stars_total": stars_total,
                "stars_period": stars_period,
            }
        )
    return items


def load_cache(path: Path) -> Optional[Dict[str, object]]:
    if not path.exists():
        return None
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None


def save_cache(path: Path, data: Dict[str, object]) -> None:
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")


def sleep_if_needed(seconds: int) -> None:
    if seconds > 0:
        time.sleep(seconds)
